using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // EF Core 9 Cosmos provider no longer supports sync I/O — use async
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — c.Discriminator still works because we preserved the
        // property name via HasDiscriminator<string>("Discriminator") in OnModelCreating.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // Sync APIs (ToList, SaveChanges, etc.) now throw — must use async equivalents
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

